import{_ as a}from"./chunks/trackbar.LGCXX873.js";import{_ as t,o as r,c as o,ae as i}from"./chunks/framework.C00B0EYs.js";const k=JSON.parse('{"title":"Tracks and Audio","description":"Manage track layers, assign files, and control track state.","frontmatter":{"title":"Tracks and Audio","description":"Manage track layers, assign files, and control track state."},"headers":[],"relativePath":"docs/guide/tracks-and-audio.md","filePath":"docs/guide/tracks-and-audio.md"}'),n={name:"docs/guide/tracks-and-audio.md"};function s(c,e,d,l,u,h){return r(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="tracks-and-audio" tabindex="-1">Tracks and Audio <a class="header-anchor" href="#tracks-and-audio" aria-label="Permalink to &quot;Tracks and Audio&quot;">​</a></h1><p>Tracks are the basic building blocks of a Motor Sound Editor project. Each track can have its own audio file, color, name, curve data, and visibility state. By organizing several tracks well, you can build complex layered results from high-frequency inverter tones to low-frequency motor body.</p><p><img src="'+a+'" alt="Track sidebar"></p><h2 id="_1-core-track-concept" tabindex="-1">1. Core track concept <a class="header-anchor" href="#_1-core-track-concept" aria-label="Permalink to &quot;1. Core track concept&quot;">​</a></h2><p>Audio in the editor is handled as layers. Each track represents an independent sound layer whose output is driven in real time by the curves stored on that track.</p><ul><li><strong>Active Track</strong>: when you click a track in the sidebar, it becomes highlighted and the main chart switches to that track&#39;s curves.</li><li><strong>Track Organization</strong>: you can group tracks by frequency band or role, such as high, mid, and base layers, to keep the project manageable.</li></ul><h2 id="_2-track-properties-and-state" tabindex="-1">2. Track properties and state <a class="header-anchor" href="#_2-track-properties-and-state" aria-label="Permalink to &quot;2. Track properties and state&quot;">​</a></h2><p>Each track comes with a small set of controls for editing and preview behavior:</p><ul><li><strong>Name</strong>: rename the track to something recognizable, such as <code>Inverter_High</code> or <code>Cooling_Fan</code>.</li><li><strong>Color</strong>: the chosen color appears in both the sidebar and the chart, making curves easier to distinguish.</li><li><strong>Show / Hide</strong>: controls whether the track remains visible in the chart. In the current implementation, hidden tracks are also excluded from preview playback.</li><li><strong>Mute</strong>: disables the track&#39;s audio output while keeping its editing data intact.</li></ul><h2 id="_3-audio-asset-management" tabindex="-1">3. Audio asset management <a class="header-anchor" href="#_3-audio-asset-management" aria-label="Permalink to &quot;3. Audio asset management&quot;">​</a></h2><p>The core of each track is the source audio file bound to it. Motor Sound Editor uses non-destructive editing, so the original file is never rewritten.</p><ul><li><strong>File assignment</strong>: click the file picker icon or path area to import audio from the local file system.</li><li><strong>Supported formats</strong>: the current build supports <code>.wav</code> and <code>.ogg</code>.</li><li><strong>Looped preview</strong>: the editor loops the assigned audio clip automatically, so you only need to shape its behavior through curves.</li><li><strong>Replacing files</strong>: when you replace audio, the new file becomes the active resource for that track. Old files are cleaned up during Save or Save As if they are no longer referenced.</li></ul><h2 id="_4-curve-linkage" tabindex="-1">4. Curve linkage <a class="header-anchor" href="#_4-curve-linkage" aria-label="Permalink to &quot;4. Curve linkage&quot;">​</a></h2><p>Tracks and curve data are bound tightly but remain isolated from one another:</p><ul><li><strong>Separated data</strong>: every track stores its own <strong>Traction</strong> and <strong>Brake</strong> pitch/volume curves.</li><li><strong>Independent editing</strong>: editing keyframes on track A does not affect track B.</li></ul>',15)])])}const m=t(n,[["render",s]]);export{k as __pageData,m as default};
